INSERT INTO bluenote_file.file_upload_session (
    upload_id, file_id, owner_id, upload_method, upload_status, expected_size,
    expected_mime_type, upload_url_expire_at, confirmed_at, created_at, updated_at
) VALUES (
    #{uploadId}, #{fileId}, #{ownerId}, #{uploadMethod}, #{uploadStatus}, #{expectedSize},
    #{expectedMimeType}, #{uploadUrlExpireAt}, #{confirmedAt}, #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE bluenote_file.file_upload_session
SET upload_status = 'UPLOADED',
    confirmed_at = #{confirmedAt},
    updated_at = #{updatedAt}
WHERE upload_id = #{uploadId}
  AND upload_status IN ('INIT', 'UPLOADED')

UPDATE bluenote_file.file_upload_session
SET upload_status = 'EXPIRED',
    updated_at = #{updatedAt}
WHERE upload_id = #{uploadId}
  AND upload_status = 'INIT'
